update ai_chat
user_id = #{userId}, conversation_id = #{conversationId}, user_question = #{userQuestion}, ai_answer = #{aiAnswer}, knowledge_match = #{knowledgeMatch}, token_usage_input = #{tokenUsageInput}, token_usage_output = #{tokenUsageOutput}, estimated_cost = #{estimatedCost}, feedback_content = #{feedbackContent}
